sql:
SELECT patch_name
FROM patches
ORDER BY last_update DESC;

external_knowledge:
- The priority levels can be 'low', 'medium', or 'high' where 'high' is the highest; 
- The status can be 'pending', 'reviewed', or 'applied';
- Patches are forwarded when they need further review or action from other teams.

sql:
